.7,"indoor_fallback_anchor_count":3,"early_start_fit":0.85,"late_finish_fit":0.7,"full_day_fit":1,"half_day_fit":0.05,"value_priced_fit":1,"budget_traveler_fit":1,"free_admission_anchor_count":3,"total_admission_krw_per_adult":9000,"off_beaten_path_fit":0.6,"crowd_avoidance_fit":0.55,"tourist_circuit_fit":0.95,"minicoach_fit":1,"max_pax_per_vehicle":14,"jeju_city_pickup_fit":1,"airport_pickup_fit":1,"airport_drop_compatible_fit":1,"dongmun_market_drop_fit":0.95,"cruise_shore_excursion_fit":0.55,"cruise_passenger_fit":0.65,"korean_food_fit":0.95,"jeju_local_cuisine_fit":1,"mulhoe_fit":0.95,"galchi_fit":0.85,"black_pig_heritage_fit":0.85,"seafood_fit":0.95,"vegetarian_friendly_fit":0.75,"halal_friendly_fit":0.65,"omegisul_tasting_fit":1,"photo_anchor_count":5,"drone_friendly_fit":0.55,"filming_location_fit":0.85,"stair_anchor_count":1,"barrier_free_anchor_fit":0.75,"accessibility_focus_fit":0.95,"is_anchor_for_unesco_focused_traveler":true,"catalog_position":"east_jeju_unesco_focused_loop","competing_tours_count":3,"china_mainland_market_fit":0,"korea_domestic_market_fit":0,"taiwan_market_fit":1,"singapore_market_fit":1,"hong_kong_market_fit":1,"china_diaspora_overseas_market_fit":0.95,"se_asia_market_fit":0.95,"us_market_fit":0.85,"europe_market_fit":0.85,"australia_market_fit":0.85,"japan_market_fit":0.85,"lava_tube_unesco_fit":1,"unesco_world_heritage_site_count":2,"twin_world_heritage_volcanic_fit":1,"haenyeo_diving_performance_fit":1},"matching_metadata":{"primary_themes":["jeju","east_jeju","unesco_focused","world_heritage","lava_tube","haenyeo_culture","intangible_heritage","joseon_heritage"],"secondary_themes":["top_3_beach","wwii_colonial_history","tuff_cone","feng_shui_walled_town","olle_trail","k_drama_filming","haenyeo_diving_performance"],"best_for":["first_time_jeju","unesco_focused_travelers","history_lovers","couples","small_families","senior_couples","rainy_day_visitors","guests_with_evening_flights"],"not_recommended_for":["thrill_seekers","private_tour_seekers","guests_demanding_west_jeju_coverage","wheelchair_users_unable_to_climb_seongsan","checkbox_sightseers_avoiding_museums"],"anchor_pois":["Hamdeok Seoubong Beach","Seongeup Folk Village","Seongsan Ilchulbong","Haenyeo Diving Performance (Haenyeo Museum fallback)","Manjanggul Lava Tube"],"anchor_poi_keys":["hamdeok_seoubong_beach","seongeup_folk_village","seongsan_ilchulbong","jeju_haenyeo_museum","manjanggul_lava_tube"],"reviews_attribution":null,"unesco_fit_note":"unesco_fit=5 = 2 World Heritage Sites (Seongsan Ilchulbong AND Manjanggul Lava Tube — both inscribed 2007 under ''Jeju Volcanic Island and Lava Tubes'') + 1 Intangible Cultural Heritage of Humanity (Culture of Jeju Haenyeo, inscribed 2016, experienced live via the haenyeo diving performance with the Haenyeo Museum as the weather/sea fallback). Seongeup Folk Village is Korea''s national folk heritage — NOT UNESCO — and does not contribute to this score.","_internal_competing_products_note":"Comp set (internal only): Southern UNESCO sister product, same operator, $43/pax small-group rate as ceiling reference.","competing_products":["east-signature-nature-core","jeju-grand-highlights-loop","jeju-southern-top-unesco-spots-tour"],"audit_summary":"East Jeju UNESCO-anchored loop carrying TWO World Heritage Sites from the same 2007 ''Jeju Volcanic Island and Lava Tubes'' inscription in a single day — Seongsan Ilchulbong (Surtseyan tuff cone) and Manjanggul Lava Tube (world''s tallest lava column, 7.6 m) — plus UNESCO Intangible Cultural Heritage of Humanity experienced live as a haenyeo free-diving performance beside Seongsan (Haenyeo Museum fallback when the sea show is cancelled), the Important Folklore Cultural Heritage of Seongeup Folk Village (1423 founding), and Olle Trail Course 19 walking heritage at Hamdeok. UNESCO-anchored counterpart to the signature-nature sister tour, which emphasizes Seolmundae Halmang mythology + Tadao Ando architecture instead.","score_rationale":{"high_scores":{"unesco_focused_tour_fit=1.0":"Two genuine World Heritage Sites (Seongsan + Manjanggul, 2007) plus a live Intangible Cultural Heritage performance in one day — densest UNESCO concentration in the catalog","world_natural_heritage_fit=1.0":"Twin lava-tube/tuff-cone World Heritage Sites from the same 2007 inscription visited the same afternoon","haenyeo_culture_fit=1.0":"UNESCO Intangible 2016 — seen live as a haenyeo diving performance beside Seongsan, with the Haenyeo Museum as fallback","value_priced_fit=1.0":"Total ₩9,000 admission per adult (Seongsan ₩5,000 + Manjanggul ₩4,000; haenyeo performance free) for two World Heritage Sites = catalog-leading UNESCO value","rainy_day_friendly_fit=0.9":"Indoor fallback anchors (Seongeup hanok + Manjanggul cave + Haenyeo Museum) keep the day resilient; the open-air haenyeo show is the one weather-dependent element and falls back to the indoor museum","wwii_history_fit=1.0":"Hamdeok tunnels + Seongsan 18 caves both visible in the day''s narrative arc"},"low_scores":{"private_tour_fit=0.05":"Format is small-group fixed itinerary only","west_jeju_fit=0.05":"Loop deliberately east-anchored","language_japanese_fit=0.55":"WWII/colonial-history framing slightly sensitive for Japanese guests — guide trained for context"}},"differentiation_vs_signature_nature_sister":"Shares the Seongsan + Seongeup anchors but swaps the sister''s mythology/architecture framing for a UNESCO-heritage spine: Hamdeok Olle 19 + TWO 2007 World Heritage Sites (Seongsan tuff cone + Manjanggul lava tube) + live UNESCO Intangible haenyeo performance (2016). This tour = twin World Heritage Sites + strongest rain-resilient anchor count + best ₩-per-UNESCO-anchor value; sister = mythology + Pulitzer architecture + 4 K-drama filming sites. Pair complementarily for guests with 2 days on Jeju.","seasonal_window":{"best_months":["April","May","June (Hamdeok beach)","September","October"],"good_months":["March","July","August (peak beach)"],"caveat_months":["December","January (Seongsan ice)"],"peak_crowd_months":["July","August (Hamdeok summer peak)"]},"kb_anchor_version":"1.29"},"page_sections":[{"id":"hero","section_html_id":null,"component":"TourHeroSection","props":{"headlineLine1":"제주 동부 유네스코 일일 투어","headlineLine2":"투어","hero":{"imageUrl":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp","imagePosition":"center 35%","tagline":"제주 동부 최다 리뷰 투어 — 전 입장료 포함","pills":["소그룹","제주"],"meta":{"duration":"≈ 9시간 (08:30 첫 픽업, ≈ 18:00 하차)","region":"동부 제주","stops":"8개 코스","rating":0,"ratingStars":5}}}},{"id":"subnav","section_html_id":null,"component":"TourTabsNav","props":{"subnavItems":[{"id":"overview","label":"투어 개요"},{"id":"itinerary","label":"상세 일정"},{"id":"details","label":"유의사항"},{"id":"faq","label":"자주 묻는 질문"},{"id":"reviews","label":"여행자 후기"}]}},{"id":"overview","section_html_id":"overview","component":"TourAtAGlance","props":{"glanceItems":[{"icon":"camera","label":"포토 가치","value":"높음","level":5},{"icon":"mountain","label":"경관","value":"높음","level":5},{"icon":"footprints","label":"도보","value":"보통","level":3},{"icon":"cloud-rain","label":"우천 적합성","value":"보통","level":3},{"icon":"users","label":"가족 적합도","value":"좋음","level":4},{"icon":"gauge","label":"투어 페이스","value":"균형 잡힘","level":4}]}},{"id":"atmosphere","section_html_id":null,"component":"TourAtmosphereGallery","props":{"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp","location":"함덕 서우봉해변","caption":"함덕 서우봉해변 — photo 1","alt":"함덕 서우봉해변 — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-01.webp","location":"함덕 서우봉해변","caption":"함덕 서우봉해변 — photo 2","alt":"함덕 서우봉해변 — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-02.webp","location":"함덕 서우봉해변","caption":"함덕 서우봉해변 — photo 3","alt":"함덕 서우봉해변 — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-04.we