ehicle":14,"jeju_city_pickup_fit":1,"airport_pickup_fit":1,"airport_drop_compatible_fit":1,"dongmun_market_drop_fit":0.95,"cruise_shore_excursion_fit":0.55,"cruise_passenger_fit":0.65,"korean_food_fit":0.95,"jeju_local_cuisine_fit":1,"mulhoe_fit":0.95,"galchi_fit":0.85,"black_pig_heritage_fit":0.85,"seafood_fit":0.95,"vegetarian_friendly_fit":0.75,"halal_friendly_fit":0.65,"omegisul_tasting_fit":1,"photo_anchor_count":5,"drone_friendly_fit":0.55,"filming_location_fit":0.85,"stair_anchor_count":1,"barrier_free_anchor_fit":0.75,"accessibility_focus_fit":0.95,"is_anchor_for_unesco_focused_traveler":true,"catalog_position":"east_jeju_unesco_focused_loop","competing_tours_count":3,"china_mainland_market_fit":0,"korea_domestic_market_fit":0,"taiwan_market_fit":1,"singapore_market_fit":1,"hong_kong_market_fit":1,"china_diaspora_overseas_market_fit":0.95,"se_asia_market_fit":0.95,"us_market_fit":0.85,"europe_market_fit":0.85,"australia_market_fit":0.85,"japan_market_fit":0.85,"lava_tube_unesco_fit":1,"unesco_world_heritage_site_count":2,"twin_world_heritage_volcanic_fit":1,"haenyeo_diving_performance_fit":1},"matching_metadata":{"primary_themes":["jeju","east_jeju","unesco_focused","world_heritage","lava_tube","haenyeo_culture","intangible_heritage","joseon_heritage"],"secondary_themes":["top_3_beach","wwii_colonial_history","tuff_cone","feng_shui_walled_town","olle_trail","k_drama_filming","haenyeo_diving_performance"],"best_for":["first_time_jeju","unesco_focused_travelers","history_lovers","couples","small_families","senior_couples","rainy_day_visitors","guests_with_evening_flights"],"not_recommended_for":["thrill_seekers","private_tour_seekers","guests_demanding_west_jeju_coverage","wheelchair_users_unable_to_climb_seongsan","checkbox_sightseers_avoiding_museums"],"anchor_pois":["Hamdeok Seoubong Beach","Seongeup Folk Village","Seongsan Ilchulbong","Haenyeo Diving Performance (Haenyeo Museum fallback)","Manjanggul Lava Tube"],"anchor_poi_keys":["hamdeok_seoubong_beach","seongeup_folk_village","seongsan_ilchulbong","jeju_haenyeo_museum","manjanggul_lava_tube"],"reviews_attribution":null,"unesco_fit_note":"unesco_fit=5 = 2 World Heritage Sites (Seongsan Ilchulbong AND Manjanggul Lava Tube — both inscribed 2007 under ''Jeju Volcanic Island and Lava Tubes'') + 1 Intangible Cultural Heritage of Humanity (Culture of Jeju Haenyeo, inscribed 2016, experienced live via the haenyeo diving performance with the Haenyeo Museum as the weather/sea fallback). Seongeup Folk Village is Korea''s national folk heritage — NOT UNESCO — and does not contribute to this score.","_internal_competing_products_note":"Comp set (internal only): Southern ユネスコ sister product, same operator, $43/pax small-group rate as ceiling reference.","competing_products":["east-signature-nature-core","jeju-grand-highlights-loop","jeju-southern-top-unesco-spots-tour"],"audit_summary":"East Jeju UNESCO-anchored loop carrying TWO World Heritage Sites from the same 2007 ''Jeju Volcanic Island and Lava Tubes'' inscription in a single day — Seongsan Ilchulbong (Surtseyan tuff cone) and Manjanggul Lava Tube (world''s tallest lava column, 7.6 m) — plus UNESCO Intangible Cultural Heritage of Humanity experienced live as a haenyeo free-diving performance beside Seongsan (Haenyeo Museum fallback when the sea show is cancelled), the Important Folklore Cultural Heritage of Seongeup Folk Village (1423 founding), and Olle Trail Course 19 walking heritage at Hamdeok. UNESCO-anchored counterpart to the signature-nature sister tour, which emphasizes Seolmundae Halmang mythology + Tadao Ando architecture instead.","score_rationale":{"high_scores":{"unesco_focused_tour_fit=1.0":"Two genuine World Heritage Sites (Seongsan + Manjanggul, 2007) plus a live Intangible Cultural Heritage performance in one day — densest UNESCO concentration in the catalog","world_natural_heritage_fit=1.0":"Twin lava-tube/tuff-cone World Heritage Sites from the same 2007 inscription visited the same afternoon","haenyeo_culture_fit=1.0":"UNESCO Intangible 2016 — seen live as a haenyeo diving performance beside Seongsan, with the Haenyeo Museum as fallback","value_priced_fit=1.0":"Total ₩9,000 admission per adult (Seongsan ₩5,000 + Manjanggul ₩4,000; haenyeo performance free) for two World Heritage Sites = catalog-leading UNESCO value","rainy_day_friendly_fit=0.9":"Indoor fallback anchors (Seongeup hanok + Manjanggul cave + Haenyeo Museum) keep the day resilient; the open-air haenyeo show is the one weather-dependent element and falls back to the indoor museum","wwii_history_fit=1.0":"Hamdeok tunnels + Seongsan 18 caves both visible in the day''s narrative arc"},"low_scores":{"private_tour_fit=0.05":"Format is small-group fixed itinerary only","west_jeju_fit=0.05":"Loop deliberately east-anchored","language_japanese_fit=0.55":"WWII/colonial-history framing slightly sensitive for Japanese guests — guide trained for context"}},"differentiation_vs_signature_nature_sister":"Shares the Seongsan + Seongeup anchors but swaps the sister''s mythology/architecture framing for a UNESCO-heritage spine: Hamdeok Olle 19 + TWO 2007 World Heritage Sites (Seongsan tuff cone + Manjanggul lava tube) + live UNESCO Intangible haenyeo performance (2016). This tour = twin World Heritage Sites + strongest rain-resilient anchor count + best ₩-per-UNESCO-anchor value; sister = mythology + Pulitzer architecture + 4 K-drama filming sites. Pair complementarily for guests with 2 days on Jeju.","seasonal_window":{"best_months":["April","May","June (Hamdeok beach)","September","October"],"good_months":["March","July","August (peak beach)"],"caveat_months":["December","January (Seongsan ice)"],"peak_crowd_months":["July","August (Hamdeok summer peak)"]},"kb_anchor_version":"1.29"},"page_sections":[{"id":"hero","section_html_id":null,"component":"TourHeroSection","props":{"headlineLine1":"済州東部ユネスコ日帰りツアー","headlineLine2":"ツアー","hero":{"imageUrl":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp","imagePosition":"center 35%","tagline":"済州東部で最も口コミが多いツアー — 全入場料込み","pills":["少人数","東済州","全入場料込み"],"meta":{"duration":"≈ 9時間（最初のお迎え8:30、解散≈18:00）","region":"東済州","stops":"8見どころ","rating":0,"ratingStars":5}}}},{"id":"subnav","section_html_id":null,"component":"TourTabsNav","props":{"subnavItems":[{"id":"overview","label":"概要"},{"id":"itinerary","label":"行程"},{"id":"details","label":"詳細情報"},{"id":"faq","label":"よくある質問"},{"id":"reviews","label":"クチコミ"}]}},{"id":"overview","section_html_id":"overview","component":"TourAtAGlance","props":{"glanceItems":[{"icon":"camera","label":"写真映え度","value":"高い","level":5},{"icon":"mountain","label":"景観の充実度","value":"高い","level":5},{"icon":"footprints","label":"歩行難易度","value":"普通","level":3},{"icon":"cloud-rain","label":"雨天適性","value":"普通","level":3},{"icon":"users","label":"ファミリー適性","value":"良好","level":4},{"icon":"gauge","label":"ペース","value":"バランス良好","level":4}]}},{"id":"atmosphere","section_html_id":null,"component":"TourAtmosphereGallery","props":{"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp","location":"咸徳ビーチ","caption":"咸徳ビーチ — photo 1","alt":"咸徳ビーチ — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-01.webp","location":"咸徳ビーチ","caption":"咸徳ビーチ — photo 2","alt":"咸徳ビーチ — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-02.webp","location":"咸徳ビーチ","caption":"咸徳ビーチ — photo 3","alt":"咸徳ビーチ — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-04.webp","location":"咸徳ビーチ","caption":"咸徳ビーチ — photo 4","alt":"咸徳ビーチ — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-37-51.webp","location":"城邑民俗村（ユネスコ遺産）","caption":"城邑民俗村（ユネスコ遺産） — photo 1","alt":"城邑民俗村（ユネスコ遺産） — gallery image 1"},{"id":6,"type":"photo","src":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-38-22.webp","location":"城邑民俗村（ユネスコ遺産）","caption":"城邑民俗村（ユネスコ遺産） — photo 2","alt":"城邑民俗村（ユネスコ遺産） — gallery image 2"},{"id":7,"type":"photo","src":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-42-26.webp","location":"城邑民俗村（ユネスコ遺産）","caption":"城邑民俗村（ユネスコ遺産） — photo 3","alt":"城邑民俗村（ユネスコ遺産） — gallery image 3"},{"id":8,"type":"photo","src":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-42-34.webp","location":"城邑民俗村（ユネスコ遺産）","caption":"城邑民俗村（ユネスコ遺産） — photo 4","alt":"城邑民俗村（ユネスコ遺産） — gallery image 4"},{"id":9,"type":"photo","src":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-11-12-24-47.webp","location":"城邑民俗村（ユネスコ遺産）","caption":"城邑民俗村（ユネスコ遺産） — photo 6","alt":"城邑民俗村（ユネスコ遺産） — gallery image 6"},{"id":10,"type":"photo","src":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 1","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 1"},{"id":11,"type":"photo","src":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 2","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 2"},{"id":12,"type":"photo","src":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 3","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 3"},{"id":13,"type":"photo","src":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 4","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 4"},{"id":14,"type":"photo","src":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-10.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 5","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 5"},{"id":15,"type":"photo","src":"/images/tours/seongsan-ilchulbong/photo-006.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 6","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 6"},{"id":16,"type":"photo","src":"/images/tours/seongsan-ilchulbong/seongsan-haenyeo-show-ai.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 12","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 12"},{"id":17,"type":"photo","src":"/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-16.webp","location":"海女の素潜り実演（実演中止時は海女博物館）","caption":"海女の素潜り実演（実演中止時は海女博物館） — photo 1","alt":"海女の素潜り実演（実演中止時は海女博物館） — gallery image 1"},{"id":18,"type":"photo","src":"/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-17.webp","location":"海女の素潜り実演（実演中止時は海女博物館）","caption":"海女の素潜り実演（実演中止時は海女博物館） — photo 2","alt":"海女の素潜り実演（実演中止時は海女博物館） — gallery image 2"},{"id":19,"type":"photo","src":"/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-18.webp","location":"海女の素潜り実演（実演中止時は海女博物館）","caption":"海女の素潜り実演（実演中止時は海女博物館） — photo 3","alt":"海女の素潜り実演（実演中止時は海女博物館） — gallery image 3"},{"id":20,"type":"photo","src":"/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp","location":"海女の素潜り実演（実演中止時は海女博物館）","caption":"海女の素潜り実演（実演中止時は海女博物館） — photo 4","alt":"海女の素潜り実演（実演中止時は海女博物館） — gallery image 4"},{"id":21,"type":"photo","src":"/images/tours/jeju-haenyeo-museum/haenyeo-sunset-silhouette-ai.webp","location":"海女の素潜り実演（実演中止時は海女博物館）","caption":"海女の素潜り実演（実演中止時は海女博物館） — photo 5","alt":"海女の素潜り実演（実演中止時は海女博物館） — gallery image 5"},{"id":22,"type":"photo","src":"/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-08.webp","location":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟）","caption":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — photo 1","alt":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — gallery image 1"},{"id":23,"type":"photo","src":"/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-22.webp","location":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟）","caption":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — photo 2","alt":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — gallery image 2"},{"id":24,"type":"photo","src":"/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-24.webp","location":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟）","caption":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — photo 3","alt":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — gallery image 3"}]}},{"id":"itinerary","section_html_id":"itinerary","component":"TourTimelineSection","props":{"itineraryStops":[{"number":1,"time":"09:00","duration":"30分","name":"お迎え（済州市内4か所）","category":"お迎え — 済州市ホテル/ハブ順次巡回","description":"**朝の無駄な移動を最小限に抑えるため、済州市内4か所に集約してのお迎えです**：同日到着の方や空港周辺ホテルの方向けの**済州国際空港**。ヨンドン/ノヒョン/旧市街ホテルゾーンの方向けの**済州市庁**。東方面出発前の最西端お迎えポイントの**河貴洞**。タプドン海岸沿いの東済州市街地の方向けの**東門伝統市場**。\n\n順序は河貴 → 空港 → 市庁 → 東門 → 国道1132号線を東へ咸徳方面へ。ミニコーチは**少人数（最大約14名）**で英語ガイド付き。**日英バイリンガルの行程表**を最初のお迎え時に配布、最初の見どころで天候ブリーフィングを行います。","image":null,"highlights":["**4か所のお迎えポイント** — 空港、市庁、河貴、東門","西から東への順序でコーチの朝の移動距離を最小化","**少人数・ミニコーチ（最大14名）**と英語ガイド","日英バイリンガルの行程表＋最初の見どころで天候ブリーフィング","済州市〜咸徳の朝の移動時間：約40分","解散は朝のお迎えと同じルート — 東門市場での立ち寄りオプションあり"],"timeUsed":["ピックアップポイントでの集合","1132号線を東へ、咸徳方面へ移動 — 約30分"],"whyOnRoute":"4か所のお迎えポイントが、空港・市内中心・旧市街・市場地区という済州市の主要ホテル＆交通ゾーンをカバーします。西から東への順序により、コーチが咸徳に約9:50に到着 — ピーク来場前の午前中の干潮時のビーチパノラマを楽しめる絶好のタイミングです。","smartNotes":{},"convenience":{},"visitBasics":{},"_role":"pickup"},{"number":2,"time":"≈ 09:50","duration":"60分","name":"咸徳ビーチ","category":"ビーチ — 済州屈指の透明度","description":"**咸徳西牛峰海水浴場 (함덕 서우봉 해변)** は**済州島ベスト3ビーチ**に常時ランクインする海岸で、**白砂のビーチ(メインストレッチ約500m、3つの連続する入江を合わせ全長約900m)** と東端から直接立ち上がる**寄生火山「西牛峰 (서우봉、「牛の頭のような形の牛望み峰」)」**のコントラストが魅力です。海の特徴的な**エメラルド・ターコイズ色**は、浅いサンゴ砂の海底が透き通った水を通して反射するために生まれます — 韓国では稀な地中海のようなコントラストが、咸徳を国内最も多く撮影されるビーチの一つに押し上げました。\n\nピーク時の夏には**1日5万人**を吸収可能ですが、春・秋の訪問は通常それほど混雑しません。**西牛峰**(山頂まで約1時間)は**3~4月にかけて菜の花の黄色いスロープ**をまとい、**東の万丈窟方面を望むパノラマ展望**が開けます。**歴史的レイヤー**: 西牛峰のすぐ西の海食崖には**第二次世界大戦中の植民地占領期に日本軍が掘削したトンネル**(神風自爆艇のシェルターと弾薬庫、城山日出峰の18洞窟と類似)があります。\n\nトンネルは公開されており、歴史的背景の解説看板が設置されています。ビーチは**済州オルレ19コース(朝天 → 金寧)**の中央区間で、トレイルの青オレンジリボンが目印です。**カフェ デルムンド (델문도 카페)** がビーチフロントの中心で、広いテラスとオーシャンビューを備え、インスタ映えとカジュアルな立ち寄りに人気です。**入場無料**、ビーチは**済州国際空港から20km / 車で約40分**(ルート1132経由)。","image":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp","highlights":["**済州ベスト3ビーチ** — エメラルドターコイズの水+白いサンゴ砂","**メインビーチ500m** + 3つの連続する入江(全長約900m)","**西牛峰寄生火山** 山頂まで約1時間 — 3~4月は菜の花の黄色いスロープ","**第二次世界大戦中の日本軍トンネル**が隣接する崖に — 神風自爆艇のシェルター","**オルレ19コース(朝天 → 金寧)** — 青オレンジリボンの目印","**カフェ デルムンド** — 広いテラス、ビーチフロントの代表的立ち寄り先","ピーク時の夏は1日**5万人**、春・秋は混雑控えめ","**入場無料**、済州国際空港から20km / 車で約40分","地中海のようなカラーコントラスト — 朝鮮半島では稀"],"timeUsed":["バス到着・駐車 — 約5分","ビーチ散策（メインエリア＋第2入り江）— 約25分","第二次世界大戦期の坑道外観見学 — 約10分","写真撮影","集合・調整時間 — 約5分"],"whyOnRoute":"**海で始まる午前の最初の停車。** 済州市内4か所でのお迎え直後、車で約40分の咸徳ソウボン海水浴場で一日を始めます。エメラルド色の海と白い砂、オルレ19コースの徒歩遺産を軽く楽しんだあと、動線は内陸の城邑、そして東部の端の城山・万丈窟へと続きます。午前の早い時間帯のため、夏の繁忙期でも比較的静かです。","_poi_meta":{"poi_key":"hamdeok_seoubong_beach","kb_version":"1.19","verified_date":"2026-04-29","sources":["Jeju Olle Foundation — Trail Course 19 official map","VisitJeju — Hamdeok Seoubong Beach","Jeju 4·3 Peace Foundation — Imperial Japanese Army tunnel records","Korea Tourism Organization — Top 3 Jeju Beaches ranking","Jocheon-eup local cultural office — Seoubong oreum trail records"]},"convenience":{"restroom":"ビーチに公衆トイレとシャワー設備","parking":"公共駐車場(夏季は有料)"},"smartNotes":{"photo":"西牛峰のシルエットとともに撮るサンセットが定番。西牛峰山頂からの俯瞰風アングルは白砂のカーブを描く","facilities":"ビーチフロント沿いに複数のカフェ。近隣にコンビニ","tip":"挾才や金寧海水浴場ほど混雑しません。東側のデルムンドカフェエリアはサンセットスポットとして人気"},"visitBasics":{"hours":"ビーチは24時間開放。海水浴シーズンは7~8月(ライフガード配置)","closed":"通年開放","admission":"無料","walking":"難易度は易しい — ビーチは平坦な砂地。西牛峰登山は難易度中程度(階段あり)"},"images":["/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp","/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-01.webp","/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-02.webp","/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-04.webp"],"imageCredits":[{"url":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp","source":"atoc-korea"},{"url":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-01.webp","source":"atoc-korea"},{"url":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-02.webp","source":"atoc-korea"},{"url":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-04.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp","location":"咸徳ビーチ","caption":"咸徳ビーチ — photo 1","alt":"咸徳ビーチ — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-01.webp","location":"咸徳ビーチ","caption":"咸徳ビーチ — photo 2","alt":"咸徳ビーチ — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-02.webp","location":"咸徳ビーチ","caption":"咸徳ビーチ — photo 3","alt":"咸徳ビーチ — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438-04.webp","location":"咸徳ビーチ","caption":"咸徳ビーチ — photo 4","alt":"咸徳ビーチ — gallery image 4"}]},{"number":3,"time":"≈ 11:00","duration":"60分","name":"城邑民俗村（ユネスコ遺産）","category":"文化遺産 — 朝鮮時代の生きた城下町","description":"**城邑民俗村**は**1423年、世宗大王の治世に鄭義縣の行政中心として築かれた、朝鮮時代の生きた城下町**です。1914年まで約500年にわたって行政の中枢として機能し、玄武岩の城壁（邑城）の内側に**伝統的な建造物110棟**が今なお住居として使われています。済州独自の建築様式 — 茅葺き屋根・玄武岩の石垣・風に傾いた木々 — が圧倒的な保存状態で残っており、国の民俗文化財に指定されています。","image":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-37-51.webp","highlights":["**1423年創建** — 世宗大王による行政中心地、**1914年まで約500年**存続","**伝統的な建造物110棟**が元の邑城（城壁都市）内に現存","**現住民が居住する「生きた」民俗村** — 博物館化された展示品ではない","済州独自の建築様式：茅葺き屋根・玄武岩・風で傾いた木","国指定民俗文化財","入場無料（ガイド付き）"],"timeUsed":["駐車＋村の解説員によるウェルカムブリーフィング——約10分","古木＋村の中心部へのウォーク——約10分","韓屋の内部見学（代表的な民家2〜3軒）——約15分","オメギスル醸造所の無料試飲——約10分","オルレ路地ウォーク＋撮影——約10分","時間の余裕——約5分"],"whyOnRoute":"**本日のコース唯一の内陸・朝鮮時代の遺産であり、地理的な転換点。** 咸徳の海岸から城山へ向かう道筋（表善の内陸）に位置し、単なる走行時間を意味のある停車に変えます。国家民俗文化財の村の石垣・茅葺き家屋と樹齢600年の老木は、午後の火山・海女遺産と対比をなす「ゆとりある文化の徒歩」を加え、一日が写真名所巡りだけに流れないようバランスを取ります。","_poi_meta":{"poi_key":"seongeup_folk_village","kb_version":"1.19","verified_date":"2026-04-29","sources":["Cultural Heritage Administration — Important Folklore Cultural Heritage designation","Korea Cultural Heritage Foundation — Seongeup Folk Village historical records","VisitJeju — Seongeup Minsok Maeul","MBC Drama Archive — Dae Jang Geum (2003–2004) filming locations","Jeju Folklore Society — Omegisul brewing tradition documentation"]},"smartNotes":{"photo":"Stone walls (dolhareubang grandfathers), thatched-roof houses with smoke holes, and traditional doors are iconic Jeju shots","facilities":"Visitor information center at entrance; English maps available","tip":"Hire a free volunteer guide at the entrance for cultural context; respect that residents actually live here — don''t enter homes uninvited"},"convenience":{"restroom":"Public restrooms at village entrance","parking":"Free parking near entrance"},"visitBasics":{"hours":"Open 24 hours (outdoor village); shops typically 09:00–17:00","closed":"Open year-round","admission":"Free for general village; some private homes charge for guided visits","walking":"Easy — flat dirt and stone paths through the village"},"images":["/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-37-51.webp","/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-38-22.webp","/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-42-26.webp","/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-42-34.webp","/images/tours/seongeup-folk-village/chatgpt-image-2026-5-11-12-24-47.webp"],"imageCredits":[{"url":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-37-51.webp","source":"atoc-korea"},{"url":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-38-22.webp","source":"atoc-korea"},{"url":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-42-26.webp","source":"atoc-korea"},{"url":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-42-34.webp","source":"atoc-korea"},{"url":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-42-34.webp","source":"atoc-korea"},{"url":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-11-12-24-47.webp","source":"atoc-korea"},{"url":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-37-51.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-37-51.webp","location":"城邑民俗村（ユネスコ遺産）","caption":"城邑民俗村（ユネスコ遺産） — photo 1","alt":"城邑民俗村（ユネスコ遺産） — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-38-22.webp","location":"城邑民俗村（ユネスコ遺産）","caption":"城邑民俗村（ユネスコ遺産） — photo 2","alt":"城邑民俗村（ユネスコ遺産） — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-42-26.webp","location":"城邑民俗村（ユネスコ遺産）","caption":"城邑民俗村（ユネスコ遺産） — photo 3","alt":"城邑民俗村（ユネスコ遺産） — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-8-07-42-34.webp","location":"城邑民俗村（ユネスコ遺産）","caption":"城邑民俗村（ユネスコ遺産） — photo 4","alt":"城邑民俗村（ユネスコ遺産） — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/seongeup-folk-village/chatgpt-image-2026-5-11-12-24-47.webp","location":"城邑民俗村（ユネスコ遺産）","caption":"城邑民俗村（ユネスコ遺産） — photo 6","alt":"城邑民俗村（ユネスコ遺産） — gallery image 6"}]},{"number":4,"time":"≈ 12:20","duration":"60分","name":"昼食（済州の地元レストラン）","category":"昼食 — 別途ご負担","description":"城邑民俗村と城山日出峰の間の約60分の昼食時間です。城山邑の漁港周辺のレストランで、黒豚、アワビのトゥッペギ、タチウオなど済州東部の郷土料理を見て回れます。昼食代は別途（約₩15,000）です。","image":null,"highlights":["**東済州の海鮮コリドー** — 城山邑漁港周辺","夏は**ムルフェ**。冬はタチウオの煮付け（カルチジョリム）が定番","昼食代は別途（≈₩15,000）。ガイドがご案内します","アレルギーや食事制限はご予約時にお知らせください"],"timeUsed":["バスで昼食場所へ移動 — 約5分","注文 + 食事 — 約45分","バスで城山日出峰入口へ — 約10分"],"whyOnRoute":"**ユネスコ核心の行程直前の充電。** 城邑から城山へ向かう道の地元レストランで、黒豚・アワビのトゥッペギ・旬の海産物など東済州の郷土料理で昼食をとります（食事代は別途）。最も活動的な午後 — 城山の登山、海女の素潜り実演、万丈窟 — に入る前に体力を補う場です。","smartNotes":{},"convenience":{},"visitBasics":{}},{"number":5,"time":"≈ 13:50","duration":"90分","name":"城山日出峰（ユネスコ世界自然遺産・日出峰）","category":"ユネスコ自然遺産 — 済州のシンボル","description":"**城山日出峰**は**5,000年前の水成噴火（スルツェイ式）で誕生した火山凝灰岩丘（タフコーン）**です。水蒸気爆発によりマグマと海水が激しく反応して形成されたこの希少な地形は、**ユネスコ世界自然遺産（2007年）・済州道ユネスコ生物圏保護区（2002年）・ユネスコ世界地質公園（2010年）**という三重の指定を受けています。標高180mの山頂には直径90mの火口が広がり、外洋に面した絶壁と済州島の田園風景を一望できます。","image":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp","highlights":["**ユネスコ三重指定**：世界自然遺産（2007年）・生物圏保護区（2002年）・世界地質公園（2010年）","**5,000年前** — 水成噴火（スルツェイ式）、マグマと海水の水蒸気爆発による誕生","**直径90mの火口**を囲む99本の岩柱","**山頂（180m）**へは30分の急な石段（≈600段）— 任意","**海岸遊歩道**（無料）でも山頂に近い景観を楽しめる","入場料：₩5,000（ツアーに含む）"],"timeUsed":["駐車＋チケット＋麓ブリーフィング——約10分","サミットデッキまでの登山（0.8km／高低差140m）——約30分","写真撮影","下山——約20分","オプション：麓での海女実演見学（1日1回14:00、悪天候時は中止の可能性あり）——約10分"],"whyOnRoute":"**一日2つの世界自然遺産の最初の一つ。** 昼食後に城山日出峰に登り（任意の登山・往復約30分）、約5,000年前の水中噴火で隆起した凝灰岩丘を見ます。登山直後に同じエリアの海で開かれる海女の素潜り実演へつながり、続いて同じ2007年登録資産である万丈窟の溶岩洞窟で締めくくり、「火山島と溶岩洞窟」の物語を一日で完成させます。","_poi_meta":{"poi_key":"seongsan_ilchulbong","kb_version":"1.19","verified_date":"2026-04-29","sources":["UNESCO WHC inscription 1264 (Jeju Volcanic Island and Lava Tubes, 2007-07-02)","UNESCO Global Geoparks Network — Jeju (2010-10 designation)","Cultural Heritage Administration — Natural Monument designation 2000-07-19","Seongsan Ilchulbong official site (seongsan.kr) — April 2025 admission update","Jeju Haenyeo Museum — UNESCO Intangible 2016 inscription record"]},"smartNotes":{"photo":"Summit view of Hallasan to the west and Udo island to the north on clear days; haenyeo black-sand beach view from descending path","facilities":"Café (Fritz Coffee 1.3km away has best exterior views of the peak); ferry to Udo Island from Seongsan Port (1.5km/15 min walk)","tip":"All stairs but well-maintained — manageable in casual clothes; family-friendly with rest stops; sunrise visits popular but crowds gather pre-dawn"},"convenience":{"restroom":"Available at entrance and base","parking":"Large free parking lot"},"visitBasics":{"hours":"Mar–Apr & Sep–Oct: 05:00–19:00; May–Aug: 04:30–20:00; Nov–Feb: 06:00–18:00 (last ticketing 1 hour before closing)","closed":"Open year-round (weather closures possible)","admission":"Adult 5,000 KRW / Youth & Child 2,500 KRW (VisitKorea reference)","walking":"Moderate — 20–30 min steady stair climb (≈ 600 stairs); benches every few minutes for rest"},"images":["/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp","/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp","/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp","/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp","/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-10.webp","/images/tours/seongsan-ilchulbong/photo-006.webp","/images/tours/seongsan-ilchulbong/seongsan-haenyeo-show-ai.webp"],"imageCredits":[{"url":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp","source":"atoc-korea"},{"url":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp","source":"atoc-korea"},{"url":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp","source":"atoc-korea"},{"url":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp","source":"atoc-korea"},{"url":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-10.webp","source":"atoc-korea"},{"url":"/images/tours/seongsan-ilchulbong/photo-006.webp","source":"atoc-korea"},{"url":"/images/tours/seongsan-ilchulbong/seongsan-haenyeo-show-ai.webp","source":"atoc-korea"},{"url":"/images/tours/seongsan-ilchulbong/photo-006.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-06.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 1","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-07.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 2","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-08.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 3","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-09.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 4","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/seongsan-ilchulbong/kakaotalk-20260510-230028438-10.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 5","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 5"},{"id":6,"type":"photo","src":"/images/tours/seongsan-ilchulbong/photo-006.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 6","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 6"},{"id":7,"type":"photo","src":"/images/tours/seongsan-ilchulbong/seongsan-haenyeo-show-ai.webp","location":"城山日出峰（ユネスコ世界自然遺産・日出峰）","caption":"城山日出峰（ユネスコ世界自然遺産・日出峰） — photo 12","alt":"城山日出峰（ユネスコ世界自然遺産・日出峰） — gallery image 12"}],"liveStatusWidget":"haenyeo"},{"number":6,"time":"≈ 15:10","duration":"50分","name":"海女の素潜り実演（実演中止時は海女博物館）","category":"ユネスコ無形文化遺産 — 済州の海女文化（2016年）のライブ","description":"**済州の海女文化**は、**2016年にユネスコ無形文化遺産**に登録された生きた遺産です。このツアーでは、博物館の展示ではなく、**城山日出峰の下の海で繰り広げられる実際の海女の素潜り実演**を見学します。生涯を海を仕事場としてきた**高齢の現役海女たち**が、酸素装備なしで*テワク*（浮き）に頼って素潜りし、潜りを終えるときに吐き出す独特の口笛のような「スムビソリ」を直接聞くことができます。 \n\n実演は通常**1日2回（約13:30・15:00）**、海の状況と天候に応じて行われ、**見学は無料**です。海女は深さと潜水能力に応じて**下軍・中軍・上軍**に分けられ、上軍は**たった一度の呼吸で10m以上**潜ります。現在活動中の海女は**4,000人未満で、大半が70歳以上**であり、直接見る素潜りの一場面一場面が、消えゆく遺産の記録となります。 \n\n**天候や波で実演が中止になる日**には、旧左邑下道里の**済州海女博物館**（大人₩1,100、屋内比率約80%、3つの展示館）で代替し、同じユネスコ無形遺産を屋内で深く学び続けます。","image":"/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp","highlights":["**ユネスコ無形文化遺産（2016年）**を、博物館ではなく**ライブの素潜り実演**で","**城山日出峰の下の海**で現役海女の実際の素潜りを見学","酸素ボンベなしで*テワク*ひとつで — 上軍は**一呼吸で10m以上**潜水","潜り終わりの独特な**スムビソリ**を直接聴取","実演は通常**1日2回（約13:30・15:00）**、**見学無料**、天候・海の状況に応じて実施","現役海女**4,000人未満・大半が70歳以上** — 消えゆく遺産","**実演中止時は海女博物館**（大人₩1,100、屋内80%、3つの展示館）で代替","城山日出峰から**徒歩・車で5分** — 動線のロスがない自然な接続"],"timeUsed":["城山日出峰から実演会場へ移動 — 約5分","実演の案内 + 場所取り — 約5分","海女の素潜り実演見学 — 約30分","写真 + 質疑 — 約5分","集合 + 移動の余裕 — 約5分"],"whyOnRoute":"**ユネスコ無形遺産を「展示」ではなく「現場」で出会うクライマックス。** 城山日出峰の登山・見学を終えた直後、同じエリアの海で開かれる海女の素潜り実演へ自然につながります（移動5分）。凝灰岩丘の火山地質（世界自然遺産）を見た目で、その海で生きてきた海女の無形遺産（2016年）をそのまま続けて見る構成は、東部コースならではの「火山 + 人」の物語を完成させます。実演は無料で、通常は午後の時間帯に開かれるため動線とも相性がよいです。**ただし海や天候によって中止になることがあり**、その日には下道里の海女博物館の屋内見学で代替し、**どんな天候でも海女遺産の体験を保証**します。","_poi_meta":{"poi_key":"jeju_haenyeo_museum","kb_version":"1.29","verified_date":"2026-04-29","sources":["UNESCO Intangible Cultural Heritage — Culture of Jeju Haenyeo (2016 inscription)","Jeju Haenyeo Museum official site (haenyeo.go.kr)","VisitJeju — Seongsan Haenyeo diving performance","Jeju Special Self-Governing Province — haenyeo population census records"]},"convenience":{"restroom":"実演会場近く / 博物館内に複数","parking":"実演会場・博物館ともに無料駐車"},"smartNotes":{"photo":"テワクに頼って浮かび上がる海女のシルエットと、城山日出峰を背景にした海のカットが象徴的です。","facilities":"実演会場近くのお手洗い・駐車 / 中止時は海女博物館のカフェ・お土産ショップ・英語案内を利用","tip":"実演時刻は当日の海の状況によって変動するため、ガイドが現場でご案内します。帽子・サングラスなど日差し対策をおすすめします。"},"visitBasics":{"hours":"実演は通常13:30・15:00（当日の海・天候により変動）/ 海女博物館09:00〜18:00（最終入場17:00）","closed":"実演：天候・波の際は中止 / 博物館：月曜・1月1日・ソルラル・秋夕休館","admission":"素潜り実演の見学は無料 / 代替時は海女博物館 大人1,100ウォン・青少年800ウォン・子ども500ウォン","walking":"易しい — 海岸からの見学、博物館での代替時はエレベーター完備の屋内"},"images":["/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-16.webp","/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-17.webp","/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-18.webp","/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp","/images/tours/jeju-haenyeo-museum/haenyeo-sunset-silhouette-ai.webp"],"imageCredits":[{"url":"/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-16.webp","source":"atoc-korea"},{"url":"/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-17.webp","source":"atoc-korea"},{"url":"/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-18.webp","source":"atoc-korea"},{"url":"/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp","source":"atoc-korea"},{"url":"/images/tours/jeju-haenyeo-museum/haenyeo-sunset-silhouette-ai.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-16.webp","location":"海女の素潜り実演（実演中止時は海女博物館）","caption":"海女の素潜り実演（実演中止時は海女博物館） — photo 1","alt":"海女の素潜り実演（実演中止時は海女博物館） — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-17.webp","location":"海女の素潜り実演（実演中止時は海女博物館）","caption":"海女の素潜り実演（実演中止時は海女博物館） — photo 2","alt":"海女の素潜り実演（実演中止時は海女博物館） — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/jeju-haenyeo-museum/kakaotalk-20260510-230009595-18.webp","location":"海女の素潜り実演（実演中止時は海女博物館）","caption":"海女の素潜り実演（実演中止時は海女博物館） — photo 3","alt":"海女の素潜り実演（実演中止時は海女博物館） — gallery image 3"},{"id":4,"type":"photo","src":"/images/tours/jeju-haenyeo-museum/haenyeo-sunset-diving-ai.webp","location":"海女の素潜り実演（実演中止時は海女博物館）","caption":"海女の素潜り実演（実演中止時は海女博物館） — photo 4","alt":"海女の素潜り実演（実演中止時は海女博物館） — gallery image 4"},{"id":5,"type":"photo","src":"/images/tours/jeju-haenyeo-museum/haenyeo-sunset-silhouette-ai.webp","location":"海女の素潜り実演（実演中止時は海女博物館）","caption":"海女の素潜り実演（実演中止時は海女博物館） — photo 5","alt":"海女の素潜り実演（実演中止時は海女博物館） — gallery image 5"}]},{"number":7,"time":"≈ 16:30","duration":"55分","name":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟）","category":"ユネスコ世界自然遺産 — 拒文オルム溶岩洞窟系（2007年登録）","description":"**万丈窟（マンジャングル溶岩洞窟）**は、約**8,000年前に漢拏山の側火山である拒文オルムから噴出した溶岩**が形成した溶岩洞窟で、**2007年に城山日出峰・漢拏山とともに「済州火山島と溶岩洞窟群」という名称でユネスコ世界自然遺産に登録**されました。城山日出峰と**同一の単一登録資産**に属するため、このツアーは一日で**2つの世界自然遺産**をともに巡ります。 \n\n全長は約**7.4km**（連結区間を含めると13〜15km）に及ぶ世界最大級の溶岩洞窟で、主通路は**幅18m・高さ23〜25m**に達します。天井の崩落でできた3つの入口のうち、**第2入口の約1km区間のみが一般公開**されており、入ったら同じ道を引き返す**往復約30〜45分**のコースです。公開区間の終点には**高さ7.6mの世界最大の溶岩石柱**があり、万丈窟を象徴するフォトスポットです。 \n\n洞窟内部は**年間を通じて11〜13℃**に保たれ、夏は涼しく冬は暖かく感じられますが、床が暗くやや湿っているため、**上着と滑り止めの靴**をおすすめします。**国家天然記念物**にも指定されています。入場料は**大人₩4,000（団体₩3,000）/ 青少年・子ども₩2,000**、営業**09:00〜18:00（最終入場17:10）**、毎月第1水曜日休業です。","image":"/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-08.webp","highlights":["**2007年ユネスコ世界自然遺産** — 城山日出峰と同じ「済州火山島と溶岩洞窟群」に登録","**一日で世界自然遺産2か所** — 城山日出峰 + 万丈窟","全長約**7.4km**、公開区間約**1km**（往復約30〜45分）","公開区間の終点に**高さ7.6mの世界最大の溶岩石柱**","主通路**幅18m・高さ23〜25m** — 世界最大級の溶岩洞窟","**拒文オルム溶岩洞窟系** — 約8,000年前に形成、国家天然記念物","内部**年間を通じて11〜13℃** — 夏の避暑地、上着推奨","入場料**大人₩4,000 / 青少年・子ども₩2,000**、営業**09:00〜18:00（最終入場17:10）**"],"timeUsed":["駐車 + チケット購入 + 入場 — 約5分","第2入口の下り + 洞窟への進入 — 約5分","公開区間1kmの往復（溶岩石柱まで）— 約30分","案内センターでの溶岩洞窟形成解説 — 約10分","集合 + 移動の余裕 — 約5分"],"whyOnRoute":"**本日のコース2つ目のユネスコ世界自然遺産であり、自然のフィナーレ。** 城山日出峰（トリプル・ユネスコの凝灰岩丘）と海女の素潜り実演（無形文化遺産）を巡ったあと、金寧（キムニョン）に位置する万丈窟は、城山から済州市へ戻る動線上に自然に収まります。城山日出峰と**同じ2007年の単一登録資産**であるため、両者を一日で組み合わせれば「火山島と溶岩洞窟」というユネスコのナラティブが完成します。午後の遅い時間帯への配置は、**日中の暑さと団体の混雑を避け**、屋外の行程のあとに**年間を通じて11〜13℃の涼しい洞窟**で一日を締めくくる快適な流れを生み出します。万丈窟が整備や荒天で閉鎖される場合は、同じ溶岩洞窟系の**日出ランド美千窟**で代替し、洞窟体験を維持します。","_poi_meta":{"poi_key":"manjanggul_lava_tube","kb_version":"1.29","verified_date":"2026-04-29","sources":["visitjeju.net (Visit Jeju official)","english.visitkorea.or.kr","jeju.go.kr/geopark","UNESCO Jeju Volcanic Island and Lava Tubes (whc.unesco.org)","Wikipedia Manjanggul (Dec 2025)"]},"convenience":{"restroom":"入口の案内センターにお手洗い","parking":"入口に無料駐車場"},"smartNotes":{"photo":"公開区間の終点にある**高さ7.6mの世界最大の溶岩石柱**が象徴的なカットで、幅18m・高さ23mの長い通路へ向けた遠近の写真もスケールが圧巻です。","facilities":"入口駐車場横の案内センターで溶岩洞窟の形成過程を説明しています — 入場前に10分の見学をおすすめします。洞窟内部に売店はありません。","tip":"夏でも上着をお持ちください（内部11〜13℃）。床が湿っていて暗いため、滑り止めの靴がよいでしょう。整備で閉鎖されることがあるため、訪問日の営業有無を事前にご確認ください。"},"visitBasics":{"hours":"09:00〜18:00（最終入場17:10）","closed":"毎月第1水曜日 / 豪雨時は臨時休業","admission":"大人4,000ウォン（団体3,000ウォン）/ 青少年・子ども2,000ウォン（団体1,500ウォン）","walking":"普通 — 平坦な1kmの往復、洞窟入口の階段の下り、床がやや凹凸ありで湿っている"},"images":["/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-08.webp","/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-22.webp","/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-24.webp"],"imageCredits":[{"url":"/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-08.webp","source":"atoc-korea"},{"url":"/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-22.webp","source":"atoc-korea"},{"url":"/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-24.webp","source":"atoc-korea"}],"galleryItems":[{"id":1,"type":"photo","src":"/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-08.webp","location":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟）","caption":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — photo 1","alt":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — gallery image 1"},{"id":2,"type":"photo","src":"/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-22.webp","location":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟）","caption":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — photo 2","alt":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — gallery image 2"},{"id":3,"type":"photo","src":"/images/tours/ilchulland/chatgpt-image-2026-5-8-07-49-24.webp","location":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟）","caption":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — photo 3","alt":"万丈窟（マンジャングル溶岩洞窟）（ユネスコ世界自然遺産・溶岩洞窟） — gallery image 3"}]},{"number":8,"time":"≈ 17:45","duration":"30分","name":"解散（2か所＋東門市場オプション）","category":"解散 — 済州市内3か所","description":"**解散は朝のお迎えと逆順序**で行い、東門伝統市場での立ち寄りオプションがあります：**東門伝統市場** — 済州でも人気の夜市で海鮮・タンジェリン・屋台グルメが並びます。**済州市庁** — 市内ホテルゾーン。**済州国際空港** — 当日便の方に最適。","image":null,"highlights":["**3か所の解散ポイント** — 東門市場、市庁、空港","**東門伝統市場** — 済州で最も人気の夜市、海鮮＋タンジェリン＋屋台グルメ","当日便の方は空港解散が利用可能","解散時刻：約18:00（当日の状況により変動）"],"timeUsed":["海女博物館から東門市場へバス移動 — 約25分","東門市場で降車 — 5分","バスで市庁方面へ移動 — 約10分","市庁で降車 — 5分","バスで空港方面へ移動 — 約15分","空港で降車 — 5分"],"whyOnRoute":"東門市場への立ち寄りは、ツアーの終わりにもう一度済州らしい体験を加えるオプションです。当日便の方には空港への直接解散もご用意しています。","smartNotes":{},"convenience":{},"visitBasics":{},"_role":"dropoff"}]}},{"id":"day_flow","section_html_id":null,"component":"TourDayFlowSection","props":{"routeFlowStops":[{"name":"済州市＋空港ピックアップ","type":"origin","theme":"出発"},{"name":"咸徳西牛峰ビーチ","type":"secondary","theme":"ビーチ"},{"name":"城邑民俗村","type":"primary","theme":"伝統村"},{"name":"昼食","type":"meal","theme":"食事"},{"name":"城山日出峰（ユネスコ）","type":"primary","theme":"ユネスコ火山地形"},{"name":"海女の素潜り実演","type":"primary","theme":"海女の無形遺産"},{"name":"万丈窟（ユネスコ）","type":"primary","theme":"ユネスコ溶岩洞窟"},{"name":"済州市降車","type":"return","theme":"帰着"}],"routePhases":[{"phase":"お迎えと海岸出発","duration":"約1時間","description":"済州市内4か所でのお迎え（08:30〜09:05）後、咸徳ソウボン海水浴場へ移動。"},{"phase":"海岸から内陸の文化遺産へ","duration":"約2時間","description":"咸徳ソウボン海水浴場（60分）→ 城邑民俗村（朝鮮時代の国家民俗文化財、60分）。"},{"phase":"昼食","duration":"約1時間","description":"城山近くの地元レストラン — 黒豚、アワビのトゥッペギ、旬の海産物。昼食代は別途。"},{"phase":"ユネスコ核心","duration":"約3時間","description":"城山日出峰（任意の登山）→ 海女の素潜り実演（中止時は海女博物館）→ 万丈窟の溶岩洞窟（ユネスコ世界自然遺産）。"},{"phase":"帰路","duration":"約1時間","description":"金寧 → 済州市へ移動 + 2か所および東門市場で下車。"}],"routeShapeIntro":{"title":"一日の流れ","subtitle":"東の端から島の2つのユネスコ世界自然遺産を一日でつなぐ東済州ループです — 城山日出峰（凝灰岩丘）と万丈窟（溶岩洞窟）、いずれも2007年に同じ資産として登録。さらにユネスコ無形遺産である海女の素潜り実演まで加えます。効率的なコースで主要見どころの混雑を避けます。"}}},{"id":"details","section_html_id":"details","component":"TourFitSection","props":{"whyTourWorks":{"bestFor":["この地域の初訪問者","カップル","大人ファミリー","充実した一日を楽しめるアクティブな旅行者","ユネスコ世界遺産をめぐりたい旅行者"],"lessIdealFor":["歩行を最小限にしたい旅行者","ベビーカーが必要なグループ","当日フライトまでの時間が限られた旅行者"],"routeLogicSections":[{"title":"このルートの推薦理由","icon":"route","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"一日でユネスコ世界自然遺産2か所 + 無形遺産","detail":"城山日出峰と万丈窟は、2007年に「済州火山島と溶岩洞窟群」としてともに登録された世界自然遺産です。さらに2016年の無形文化遺産である海女の素潜り実演まで加え、一日で三重のユネスコ遺産を見ます。"},{"label":"本物の万丈窟 — もはや代替ではない、本家のユネスコ溶岩洞窟","detail":"かつての休業期には美千窟で代替していましたが、いまは世界最大級の溶岩洞窟であり、高さ7.6mの世界最大の溶岩石柱を擁する万丈窟を直接訪ねます。"},{"label":"全入場料込み — この価格帯ならではの価値","detail":"城山日出峰₩5,000 + 万丈窟₩4,000（城邑は無料、海女の素潜り実演は無料）— 2つの世界自然遺産をわずか₩9,000の入場料に含めます。"},{"label":"城山日出峰の登山は任意","detail":"往復約30分の火口の縁の登山は傾斜があり、すべての方に向くわけではありません。階段なしで近い眺めを楽しめる海岸の周遊路もあるため、体力に応じてお選びいただけます。"}]}]}}},{"id":"practical","section_html_id":null,"component":"TourPracticalDetails","props":{"practicalAccordionItems":[{"id":"inclusions","title":"含まれるもの","preview":"エアコン付きミニコーチ、認定英語・中国語ガイド、全入場料込み…","content":["エアコン付きミニコーチ、認定英語・中国語ガイド、全入場料（城山日出峰₩5,000、城邑民俗村無料、日出ランド・密川洞窟₩12,000、海女博物館₩1,100、咸徳ビーチ無料）、燃料・通行料・駐車場代。","含まれないもの：昼食（≈₩15,000）、飲料、チップ。"]},{"id":"pickup","title":"お迎えと解散","preview":"4か所での順次お迎え：オーシャンスイーツ済州（8:30）、済州空港ゲート1 1階…","content":["4か所での順次お迎え：オーシャンスイーツ済州（8:30）、済州空港ゲート1 1階国内線到着口（8:45 — 南部ツアーとは異なるゲートです）、LOTTEシティホテル済州（8:55）、新羅免税店済州（9:05）。","ご予約時に最寄りの場所をお選びください。","前日にWhatsAppにてご確認いたします。"]},{"id":"walking","title":"歩行と地形","preview":"中程度の難易度。","content":["中程度の難易度。","咸徳ビーチは平坦な砂地。","城邑民俗村は土の道と石垣。","城山日出峰の火口の縁の登山は約30分の急な石段（省略可）。","海女の素潜り実演は平坦な海岸からの見学。","万丈窟は約1kmの平坦な往復、洞窟入口の階段と内部のやや凹凸あり・湿った床面（年間を通じて11〜13℃、上着推奨）。","つま先を保護する靴が必須。","総歩行距離は約4〜5km。"]},{"id":"cancellation","title":"キャンセルポリシー","preview":"お迎えの24時間前まで無料キャンセル。","content":["お迎えの24時間前まで無料キャンセル。","当日キャンセルおよびノーショーは返金不可。","悪天候により城山登頂が短縮される場合がありますが、ツアー自体がキャンセルになることはありません。"]},{"id":"cave","title":"洞窟案内（万丈窟）","preview":"万丈窟はユネスコ世界自然遺産の溶岩洞窟としてコースに含まれます。","content":["万丈窟は2007年に登録されたユネスコ世界自然遺産の溶岩洞窟で、本コースに含まれます。","公開区間は約1kmの往復（約30〜45分）、終点には高さ7.6mの世界最大の溶岩石柱。","内部は年間を通じて11〜13℃と涼しいため、上着をおすすめします。","整備や天候で閉鎖される場合は、近隣の溶岩洞窟（日出ランド美千窟）で代替されることがあります — ご予約時にご確認ください。"]},{"id":"children","title":"お子様の参加とバリアフリー","preview":"城山日出峰の山頂登頂（≈600段、任意）と9時間のペースのため、10歳以上を推奨…","content":["城山日出峰の山頂登頂（≈600段、任意ですが見どころの中心）と9時間のペースのため、10歳以上を推奨しています。","小さなお子様もご参加いただけますが、登頂が負担になる場合があります。山頂へ登らず、クルーズバスツアーや桜ツアーもご検討ください。","ベビーカーは城山日出峰の階段や城邑民俗村の小道では非推奨です。"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"季節情報をご確認ください"},"tomorrow":{"temp":"—","label":"季節情報をご確認ください"},"_seasonalSummary":"東済州は島内で最も澄んだ海の眺望と最も暖かい夏気温が特徴です。城山日出峰（ソンサン・イルチュルボン）は年中風にさらされますので、薄手の上着をお持ちください。","_seasonalTemperatures":[{"season":"春（3〜5月）","range":"8–22°C","notes":"4月上旬に桜が咲き、咸徳に菜の花が広がります。"},{"season":"夏（6〜8月）","range":"22–30°C","notes":"海岸見どころは暑くても風があります。咸徳では海の色が最も美しい季節。"},{"season":"秋（9〜11月）","range":"10–24°C","notes":"最もおすすめの季節 — 城山の山頂からの眺望が最高に冴えます。"},{"season":"冬（12〜2月）","range":"3–10°C","notes":"城山の山頂は風による寒さが厳しいです。全見どころとも混雑が少ない時期。"}]},"seasonalVariations":[{"season":"春","description":"咸徳の斜面に黄色い菜の花が咲き乱れ、エメラルドの海との対比が鮮やかです。"},{"season":"夏","description":"咸徳ビーチが最も美しい季節。日照時間が長く、城山日出峰もゆとりをもって見て回れます。"},{"season":"秋","description":"城山日出峰の山頂からの眺望が最もクリアな時期。城邑民俗村は年中写真映えするです。"},{"season":"冬","description":"混雑が最も少ない季節。寒い時期には海女博物館の屋内展示がとくに魅力的です。"}]}},{"id":"booking_support","section_html_id":null,"component":"TourBookingSupportSection","props":{"bookingTrustItems":[{"icon":"check-circle","title":"地元公認催行会社","description":"許可を受けた韓国ツアー催行会社、全額保険加入済み","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600","body":"地元公認ツアー催行会社 — 東済州日帰りツアーで最も多くのクチコミを獲得しています。"},{"icon":"route","title":"ルートの専門家","description":"汎用ルートではなく、丁寧に作られた行程","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","body":"ツアー料金に含まれる全入場料：城山日出峰（₩5,000）、万丈窟（₩4,000）、城邑民俗村（無料）、海女の素潜り実演（無料）— 現地で別途お支払いいただく項目はありません。"},{"icon":"users","title":"適切なグループ規模","description":"ルートに最適なグループサイズ","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","body":"少人数ミニバス（最大14名）で、城邑の路地、万丈窟の溶岩洞窟、海女の素潜り実演をゆったりと巡ります。"}],"bookingSupportSteps":[{"timing":"予約後すぐ","title":"予約確認（即時）","detail":"行程概要付きで予約確認書をお送りします","description":"済州市ホテルのお迎え詳細付きで即時確認（市内は無料。市外は+₩70,000）。"},{"timing":"12時間前","title":"12時間前リマインダー","detail":"天候情報とルート変更のお知らせ","description":"海女実演スケジュールに関する事前ご案内（城山での実演は通常14:00（1日1回））をお送りします。どちらの時間に合わせるかご参考にどうぞ。"},{"timing":"前日の夜","title":"最終お迎え情報","detail":"正確なお迎え時刻とドライバーの連絡先","description":"前夜に最終お迎え時刻を確認いたします。"},{"timing":"当日の朝","title":"当日ルート情報","detail":"現地状況に基づく朝のブリーフィング","description":"天候や城山の山頂状況（強風時は閉鎖）に関する朝のメッセージをご案内します。"},{"timing":"ツアー中","title":"各訪問地でのガイダンス","detail":"各訪問地でのリアルタイムアドバイス","description":"各訪問地で詳しい解説をご提供：海女のユネスコ登録（2016年）、城邑の500年の行政史、溶岩トンネルの地質、城山日出峰のユネスコ三重指定など。"},{"timing":"ツアー後","title":"ツアー後サポート","detail":"フォローアップとおすすめ情報","description":"ツアー後のフィードバックをお願いしています。済州旅行に関するご質問は当日中にお答えします。"}]}},{"id":"faq","section_html_id":"faq","component":"TourFaqSection","props":{"staticQuestions":[{"id":"q1","question":"海女の素潜り実演を実際に見られますか？","answer":"はい。城山日出峰近くの海で開かれる海女の素潜り実演の見学がコースに含まれます（通常は午後、無料）。海の状況や天候によって中止になることがあり、中止時は下道里の海女博物館の屋内見学で代替して、海女遺産の体験を保証します。"},{"id":"q2","question":"城山日出峰の火口の登山を省略できますか？","answer":"可能です。階段なしでも近い写真アングルを楽しめる海岸の周遊路があります。火口の登山（往復約0.8km、約30分）は任意であり、体力に応じてお決めいただけます。"},{"id":"q3","question":"済州南部のユネスコツアーとの違いは何ですか？","answer":"同じ旅行会社のツアーです。南部ツアーは漢拏山のオルム、カメリアヒル、天帝淵滝、柱状節理、オソルロク茶畑を含みます。東部ツアーは城山日出峰、城邑民俗村、万丈窟、海女の素潜り実演を中心に進みます。"},{"id":"q4","question":"万丈窟が閉まる日はどうなりますか？","answer":"万丈窟はユネスコ世界自然遺産の溶岩洞窟としてコースに含まれています。ただし整備や天候（豪雨など）で閉鎖される日には、同じ溶岩洞窟系の日出ランド美千窟など近隣の洞窟で代替して、洞窟体験を維持します。"},{"id":"q5","question":"昼食は含まれていますか？","answer":"含まれていません。昼食代は別途（約₩15,000）で、ガイドが地元のおすすめ店をご案内します。"}]}},{"id":"reviews","section_html_id":"reviews","component":"TourReviewsSection","props":{"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"reviewsAttribution":"催行会社の市場参考資料掲載ページに基づく総合評価です。個別レビューは該当ページでご確認ください。"}},{"id":"sticky_booking","section_html_id":null,"component":"TourStickyBookingBar","props":{"note":"予約可否は決済ステップで確認されます。","price":{"amountLabel":"47","originalPriceUsd":59,"salePriceUsd":47,"discountPercent":20,"currency":"USD","per":"person"}}}],"itinerary_variants":[],"_publication":{"schema_version":"v4_canonical","last_modified":"2026-04-28","version_history":["v11","v12","v13","v14","v15","v15.2"],"fix_passes":{"v12":"P0+P1 — pickup_dropoff Schema A unification, routeFlowStops type-based, competing_products → internal slugs, anchor_poi_keys aligned","v13":"P1.5 — pickup_dropoff Schema A.2 → A.1; practicalAccordionItems / routePhases / seasonalVariations unified to V4 canonical (no Tailwind in data)","v14":"P2 — _publication uniform; duration formatting standardized; glanceItems Duration added where missing","v15":"P3 round 1 — SEO trim. seo.pageTitle rewritten to ≤65 chars (was 14/25 over 70); seo.metaDescription rewritten to ≤168 chars (was 25/25 over 170). primaryKeywords and ogImage unchanged. Hero/OG images, POI verification, review imports, and routePhases enrichment deferred to later P3 rounds.","v15.2_charter_consolidation":"Removed \"jeju-popular-sightseeing-private-car-charter-tour\" from competing_products per Jason''s one-charter-per-region rule (jeju-island-private-car-charter-tour remains as canonical Jeju charter).","v17_schema_unification":{"date":"2026-04-28","description":"Phase 1: Standardized matching_profile scores to the current 0-1 float scale used by match_tours.matching_profile.","fields_converted":43,"fields_skipped":0,"fields_already_float":0},"v17_batch2_enhancement":{"date":"2026-04-28","description":"Batch 2 deep enhancement — descriptions raised to 700-1100+ chars; KB-backed visitBasics/convenience/smartNotes/_poi_meta on all attraction stops; product profile recalibrated with verified-fact 0-1 float scores (replacing Phase 1 mechanical conversion).","_score_audit":{"_methodology":"0-1 float scale. Each score grounded in verified facts.","deltas_applied":{"unesco_fit":{"old":1,"new":1,"reasoning":"VERIFIED 1.0 — this tour is correctly named ''eastern UNESCO loop'': Seongsan = UNESCO World Heritage (Jeju Volcanic Island & Lava Tubes 2007), Haenyeo Museum = UNESCO Intangible Cultural Heritage (haenyeo culture 2016). Tour covers BOTH UNESCO categories. Strongest UNESCO-fit tour in catalogue."},"intangible_heritage_fit":{"old":1,"new":1,"reasoning":"VERIFIED 1.0 — Haenyeo Museum is the dedicated UNESCO ICH interpretation center; Seongsan haenyeo demonstration at 14:00 (1 show/day) is the live UNESCO ICH performance; Seongeup Folk Village preserves Joseon-period intangible folkways. 3 of 5 attractions carry intangible-heritage value. Highest possible score."},"walking_level":{"old":0.8,"new":0.65,"reasoning":"DOWNGRADED 0.8→0.65 with verified totals: Hamdeok beach 0.5 km flat (sand + boardwalk), Seongeup ~1 km flat olle, Micheon Cave 365 m flat (leveled), Seongsan 0.8 km + 140 m gain (the only stair-heavy stop), Haenyeo Museum 100% indoor flat. Total ~3 km + only Seongsan has elevation. Tour 1 (east-signature) walks more (Seopjikoji 2.1 km extra). Verified moderate walking = 0.65 not 0.8."},"young_kids_fit":{"old":1,"new":0.75,"reasoning":"DOWNGRADED 1.0→0.75: Hamdeok beach + leveled Micheon Cave + indoor Haenyeo Museum + Seongeup folk village = 4 of 5 kid-friendly. ONLY Seongsan''s 300-500 steps challenge under-7s. Mechanical 1.0 was overstated; verified 0.75 is honest."},"stroller_fit":{"old":0.4,"new":0.5,"reasoning":"UPGRADED 0.4→0.50: Hamdeok flat + Micheon Cave LEVELED FLOOR (verified — vs Manjanggul''s uneven natural floor) + Haenyeo Museum 100% accessible + Seongeup main alleys + ONLY Seongsan stairs unsuitable. 4/5 stroller-friendly = 0.50 not the previous 0.4. Specifically chose Micheon vs Manjanggul for accessibility."},"mobility_friendly_fit":{"old":0.6,"new":0.65,"reasoning":"UPGRADED 0.6→0.65: Verified 4 of 5 stops mobility-friendly (Hamdeok flat, Micheon leveled, Haenyeo Museum elevators, Seongeup flat alleys), only Seongsan summit not accessible. The choice of Micheon Cave instead of Manjanggul specifically supports this."},"weather_sensitivity":{"old":1,"new":0.75,"reasoning":"DOWNGRADED 1.0→0.75 — verified: Haenyeo Museum 100% indoor, Micheon Cave 100% indoor and stable temperature year-round, Seongeup hanok have shelter. Only Hamdeok and Seongsan are weather-exposed. The ''all UNESCO'' name made the prior score look high, but indoor ratio is actually reasonable. Mechanical 1.0 overstated."},"indoor_ratio":{"old":0.1,"new":0.4,"reasoning":"MAJOR CORRECTION: Verified breakdown — Hamdeok 100% outdoor, Seongeup ~30% indoor (visiting hanok interiors), Micheon Cave 100% indoor, Seongsan 5% indoor (visitor center only), Haenyeo Museum 100% indoor. Time-weighted indoor ratio ~40%, NOT the previous 10%. Correcting a documentation error."},"rain_fit":{"old":0.6,"new":0.75,"reasoning":"UPGRADED 0.6→0.75: With Micheon Cave (indoor), Haenyeo Museum (indoor), and Seongeup hanok interiors as rain refuges, this tour holds up MUCH better in rain than the mechanical 0.6 implied. Hamdeok and Seongsan suffer in rain but the rest is fine. Verified."},"iconic_landmark_fit":{"old":1,"new":0.85,"reasoning":"VERIFIED 0.85: Seongsan = universally iconic (triple UNESCO crown). Hamdeok = Top 3 Jeju beach. Seongeup + Haenyeo Museum = nationally significant culture (UNESCO ICH for Haenyeo). Micheon Cave = secondary lava tube. 0.85 — strong but not all 5 universally iconic."},"value_for_money_fit":{"old":1,"new":0.85,"reasoning":"Verified fees: Hamdeok free + Seongeup free + Micheon ₩12,000 + Seongsan ₩2,000 + Haenyeo Museum ₩1,100 = ~₩15,100/adult. Reasonable but Ilchul Land at ₩12,000 is the big driver. 0.85 calibrated."},"senior_fit":{"old":0.4,"new":0.55,"reasoning":"UPGRADED 0.4→0.55: With Hamdeok beach walk (flat), Micheon leveled cave, Seongeup flat alleys, Haenyeo Museum accessible — 4 of 5 stops fully senior-accessible. Only Seongsan summit excludes seniors with mobility issues (alternative: stay at base for haenyeo demo). Verified ≥0.55, much better than 0.4."},"senior_active_fit":{"old":0.6,"new":0.75,"reasoning":"UPGRADED 0.6→0.75: For active seniors, all 5 stops are achievable (Seongsan rest stops + benches make 45-60 min summit reasonable). Cultural depth (UNESCO + 600-year village + 400-year haenyeo tradition) very strong appeal for senior travelers. 0.75 verified."},"senior_general_fit":{"old":0.4,"new":0.55,"reasoning":"UPGRADED 0.4→0.55: Same logic — 4/5 stops accessible to general senior population (alternative for Seongsan = stay at base for haenyeo demonstration). 0.55 calibrated."},"beach_fit":{"old":0.6,"new":0.85,"reasoning":"UPGRADED 0.6→0.85: Hamdeok IS the dedicated beach stop — Top 3 Jeju beach (verified VisitKorea ranking). 0.6 understates this; 0.85 reflects beach as a primary tour theme."},"culture_level":{"old":1,"new":0.95,"reasoning":"Slight DOWNGRADE 1.0→0.95: Verified 3 strong cultural anchors (Seongeup 600-year town + Haenyeo 400-year tradition + Seongsan haenyeo demo). Hamdeok is recreational not cultural. 0.95 (vs east-signature''s lower) — still very strong."}}},"stops_enhanced":6,"sources":["VisitKorea","Wikipedia","UNESCO","Visit Jeju","Inside Jeju","Jeju Tourism Organization","AllTrails"]},"v17_fix1_indoor_ratio_correction":{"date":"2026-04-28","description":"Jason correction: Micheon Cave and Seongeup Folk Village are 70% outdoor. Recalculated tour-level indoor_ratio with time-weighted attraction durations and adjusted dependent fields.","computation":{"stops_time_weighted":{"hamdeok_seoubong_beach":"45min × 0.00 indoor = 0.00","seongeup_folk_village":"75min × 0.30 indoor = 22.50 (corrected from 0.50)","ilchulland_micheon_cave":"60min × 0.30 indoor = 18.00 (corrected from 0.60)","seongsan_ilchulbong":"90min × 0.05 indoor = 4.50","jeju_haenyeo_museum":"60min × 1.00 indoor = 60.00","total_indoor_min":105,"total_substantive_min":330,"computed_indoor_ratio":0.32}},"changes":{"indoor_ratio":{"old":0.4,"new":0.3,"reason":"Recalculated 105/330 = 0.32, rounded to 0.30"},"rain_fit":{"old":0.75,"new":0.55,"reason":"Only Haenyeo Museum is full refuge; Seongeup and Micheon mostly outdoor; Hamdeok and Seongsan rain-bad"},"weather_sensitivity":{"old":0.75,"new":0.7,"reason":"Still has Haenyeo Museum as anchor refuge but 70% of stop time is weather-exposed"}}}}},"liveStatusSection":"haenyeo"}'::jsonb
