  'person',
  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"jeju-eastern-unesco-spots-day-tour","locale":"zh","product_id":"jeju-eastern-unesco-spots-day-tour","seo":{"pageTitle":"东济州UNESCO景点小团一日游 | AtoC Korea","metaDescription":"9小时东济州小团环线：咸德海水浴场、城邑民俗村（联合国教科文组织民俗）、城山日出峰（联合国教科文组织）与万丈窟（联合国教科文组织）两处世界自然遗产、海女潜水表演。含全部门票。","primaryKeywords":["济州东部世界遗产旅游","城山日出峰旅游","万丈窟旅游","海女潜水表演","济州日出峰一日游"],"ogImage":"https://www.atockorea.com/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp","title":"济州东部UNESCO景点一日游 · 9小时小团 · 含全部门票 | AtoC Korea","description":"济州东部9小时小团一日游：咸德海水浴场 → 城邑民俗村 → 午餐 → 城山日出峰（联合国教科文组织）→ 海女潜水表演 → 万丈窟（联合国教科文组织）。含全部门票，持证导游。"},"catalog_card":{"thumbnail":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp","title":"济州东部UNESCO一日游","priceLabel":"每人 US$47（原价 $59，立减20%），约₩72,000","shortCardDescription":"以9小时小团环游济州东部联合国教科文组织景点。涵盖咸德海水浴场、城邑民俗村（联合国教科文组织民俗）、城山日出峰与万丈窟 — 2007年共同登录的两处联合国教科文组织世界自然遗产，以及海女潜水表演（取消时改为海女博物馆）。含全部门票，持证英语·中文导游。","tags":["小团","jeju","济州东部","unesco","性价比高","含门票"],"rating":0,"reviewCount":0,"slug":"jeju-eastern-unesco-spots-day-tour","subtitle":"小团迷你巴士，英语·中文导游 — 以9小时东部环线游览咸德海水浴场·城邑民俗村·城山日出峰（联合国教科文组织）·海女潜水表演·万丈窟（联合国教科文组织）。","region":"济州东部","duration":"9小时","stopsCount":8,"badges":["小团","济州","济州东部","世界遗产","超值定价","所有门票已包含"],"heroImage":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp"},"headlineLine1":"济州东部UNESCO一日游","headlineLine2":"一日游","price":{"amountLabel":"47","originalPriceUsd":59,"salePriceUsd":47,"discountPercent":20,"currency":"USD","per":"person"},"hero":{"imageUrl":"/images/tours/hamdeok-beach/kakaotalk-20260510-230028438.webp","imagePosition":"center 35%","tagline":"评价最高的东济州行程——全部门票已含括","pills":["小团","济州"],"meta":{"duration":"≈ 9小时（08:30首次接送，≈ 18:00下车）","region":"济州东部","stops":"8 个景点","rating":0,"ratingStars":5}},"subnavItems":[{"id":"overview","label":"行程总览"},{"id":"itinerary","label":"详细行程"},{"id":"details","label":"注意事项"},{"id":"faq","label":"常见问题"},{"id":"reviews","label":"旅客评价"}],"glanceIt